class TodoList {
  constructor() {
    this.todos = [];
    this.nextId = 1;
  }

  add(text) {
    const id = this.nextId++;
    this.todos.push({ id, text });
    return id;
  }

  remove(id) {
    const index = this.todos.findIndex(todo => todo.id === id);
    if (index !== -1) {
      this.todos.splice(index, 1);
      return true;
    }
    return false;
  }

  list() {
    return this.todos;
  }
}

module.exports = TodoList;
